INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57112235-moex-00237', 'judicial-57112235', 'judicial-57112235-moex-113-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '福克斯與史丁克孔（Fox&Stinchcomb,1999）提出監獄暴動通常有前置及突發條件，下列條件敘 述何者錯誤？', '["種族衝突與幫派等環境壓力源，及長期的擁擠空間與不足的水電等物質設施，屬監獄暴動之突發條件", "新的行政行為緊縮受刑人權益，可能導致監獄暴動發生的突發條件", "不適任的管教人員與不當的獄政管理型態與方式、假釋標準不一等，均為暴動發生的前置條件", "大眾的冷淡，提升了人犯與社會大眾疏離的感覺，人犯認為他們是社會漠視的一群，亦為暴動 的前置條件"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "bf4b5d100335", "answer_pdf_sha1": "c80fae1e3f59", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00238', 'judicial-57112235', 'judicial-57112235-moex-113-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '下列有關作業制度之合約業制的敘述，何者錯誤？', '["廠商供給材料、器械", "受刑人戒護安全管理由矯正機構負責", "廠商派遣監工之人員與收容人直接接觸，易於輸入違禁品", "廠商按照成品數目支付工資"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "bf4b5d100335", "answer_pdf_sha1": "c80fae1e3f59", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00239', 'judicial-57112235', 'judicial-57112235-moex-113-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '假釋制度是刑罰執行時，用以鼓勵受刑人自新，協助更生復歸社會的重要制度。請問下列敘述， 何者與假釋性質不符？', '["可節約刑罰執行費用", "實現刑罰威嚇原則", "符合刑期無刑之精神", "強調降低受刑人再犯率"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "bf4b5d100335", "answer_pdf_sha1": "c80fae1e3f59", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00240', 'judicial-57112235', 'judicial-57112235-moex-113-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '關於監獄工場勤務之管理，下列敘述何者正確？', '["為維護人權，受刑人作業位置勿庸規定，掌握其作業成品完成率即可", "受刑人同桌用餐人員無需限制人數，以利其人際交流", "出庭還押或接見後返回工場之受刑人，因已於中央台檢身，故進入工場時免再檢查", "收工時，應逐一清點工作器具，並放置於一定處所，如有缺損應查究原因"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "bf4b5d100335", "answer_pdf_sha1": "c80fae1e3f59", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00241', 'judicial-57112235', 'judicial-57112235-moex-113-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '我國監獄高齡（60歲以上）受刑人近十年來人數及占比呈現上升趨勢，爰此，高齡受刑人處遇對 策亦日漸受到重視。下列有關高齡受刑人特性及其處遇對策，何者錯誤？', '["高齡受刑人因年紀較大，較不易配合監獄管理", "舍房或工場應增加無障礙或防滑設施", "開發適合高齡者之文康或輔導活動", "和社會福利主管機關或更生保護會加強合作，辦理復歸轉銜安置作業"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "bf4b5d100335", "answer_pdf_sha1": "c80fae1e3f59", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00242', 'judicial-57112235', 'judicial-57112235-moex-113-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '監獄輔導人員為引導受刑人消除不良行為，依增強及削弱原則，運用增強物，藉以發展受刑人適 當行為，這是何種心理治療技術？', '["現實療法", "溝通分析療法", "環境療法", "行為療法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "bf4b5d100335", "answer_pdf_sha1": "c80fae1e3f59", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00243', 'judicial-57112235', 'judicial-57112235-moex-113-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '監獄管理嚴禁受刑人結合、隨時粉碎受刑人團體之形成，違規者均依正式之方法處理。以上管理 模式依學者JohnJ.Dilulio,Jr.之分類，係屬於下列何種獄政管理模式之特徵？', '["紐約抑制模式", "德州控制模式", "密西根責任模式", "加州共識模式"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "bf4b5d100335", "answer_pdf_sha1": "c80fae1e3f59", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00244', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '相較於傳統監獄行刑之目的，彰顯現行監獄行刑法「第1條」之基本精神及其立法之「積極目的」， 下列組合何者正確？', '["修復、嚇阻", "隔離、應報", "矯治、教化", "懲罰、痛苦"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00245', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依據監獄行刑法，下列敘述何者錯誤？', '["監獄行刑法之主管機關為法務部", "監獄之監督機關為法務部矯正署", "監獄之監督機關應派員視察監獄，每月至少一次", "少年法院法官、檢察官執行刑罰有關事項，得隨時訪視少年矯正學校、監獄"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00246', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依據監獄行刑法以及相關法規之規定，下列敘述何者正確？', '["未滿十八歲之少年受刑人，應收容於少年矯正學校，且毋庸按其性別分別收容", "收容中滿十八歲而殘餘刑期未滿三個月者，得繼續收容於少年矯正學校", "滿十八歲之少年受刑人，得依其教育需要，收容於少年矯正學校至滿二十二歲為止", "監獄行刑法所稱少年受刑人，指受法院裁判時未滿十八歲之受刑人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
